mapper.update:
UPDATE qr_code_statistics
SET receive_count = #{receiveCount}, qr_code_count = #{qrCodeCount}
WHERE id = #{id}

mapper.select:
SELECT year, month, receive_count as receiveCount, qr_code_count as qrCodeCount FROM qr_code_statistics WHERE 1=1
AND year = #{year}
ORDER BY year DESC, month DESC
